-- ─── CREATE TABLES ─────────────────────────────────────────

CREATE TABLE IF NOT EXISTS pk_outcomes (
    id          SERIAL PRIMARY KEY,
    code        VARCHAR(50) UNIQUE NOT NULL,
    name        VARCHAR(255) NOT NULL,
    created_at  TIMESTAMP DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS pk_tests (
    id          SERIAL PRIMARY KEY,
    test_no     INTEGER UNIQUE NOT NULL,
    created_at  TIMESTAMP DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS pk_questions (
    id          SERIAL PRIMARY KEY,
    test_id     INTEGER NOT NULL REFERENCES pk_tests(id) ON DELETE CASCADE,
    question_no INTEGER NOT NULL,
    page_no     INTEGER DEFAULT 0,
    subject     VARCHAR(100) DEFAULT '',
    topic       VARCHAR(255) DEFAULT '',
    outcome_id  INTEGER NOT NULL REFERENCES pk_outcomes(id) ON DELETE RESTRICT,
    created_at  TIMESTAMP DEFAULT NOW(),
    UNIQUE(test_id, question_no)
);

CREATE INDEX IF NOT EXISTS idx_pk_questions_test_id ON pk_questions(test_id);
CREATE INDEX IF NOT EXISTS idx_pk_questions_outcome_id ON pk_questions(outcome_id);

